#define REC_LENGTH 49
#define LATITUDE_POS 28
#define OPEN 10000

__kernel void calculate_distances(
    __global const char* sandbox,
    __global float* z,
    float target_lat,
    float target_long,
    int rec_count)
{
    int i = get_global_id(0);
    if (i < rec_count) {
        const char* rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        // Parse latitude from string
        int pos = 0;
        float sign = 1.0f;
        float int_val = 0.0f;
        float frac_val = 0.0f;
        float frac_div = 1.0f;

        while (rec_iter[pos] == ' ' && pos < 5) pos++;
        if (rec_iter[pos] == '-') { sign = -1.0f; pos++; }

        while (rec_iter[pos] >= '0' && rec_iter[pos] <= '9' && pos < 5) {
            int_val = int_val * 10.0f + (rec_iter[pos] - '0');
            pos++;
        }

        if (rec_iter[pos] == '.') {
            pos++;
            while (rec_iter[pos] >= '0' && rec_iter[pos] <= '9' && pos < 5) {
                frac_div *= 10.0f;
                frac_val += (rec_iter[pos] - '0') / frac_div;
                pos++;
            }
        }
        tmp_lat = sign * (int_val + frac_val);

        // Parse longitude (5 characters after latitude position)
        rec_iter += 5;
        pos = 0;
        sign = 1.0f;
        int_val = 0.0f;
        frac_val = 0.0f;
        frac_div = 1.0f;

        while (rec_iter[pos] == ' ' && pos < 5) pos++;
        if (rec_iter[pos] == '-') { sign = -1.0f; pos++; }

        while (rec_iter[pos] >= '0' && rec_iter[pos] <= '9' && pos < 5) {
            int_val = int_val * 10.0f + (rec_iter[pos] - '0');
            pos++;
        }

        if (rec_iter[pos] == '.') {
            pos++;
            while (rec_iter[pos] >= '0' && rec_iter[pos] <= '9' && pos < 5) {
                frac_div *= 10.0f;
                frac_val += (rec_iter[pos] - '0') / frac_div;
                pos++;
            }
        }
        tmp_long = sign * (int_val + frac_val);

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;
        z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
    }
}

__kernel void update_neighbors(
    __global const float* z,
    __global const char* sandbox,
    __global char* neighbor_entries,
    __global float* neighbor_distances,
    int rec_count,
    int k,
    float open_dist)
{
    int i = get_global_id(0);
    if (i < rec_count) {
        float max_dist = -1.0f;
        int max_idx = 0;

        for (int j = 0; j < k; j++) {
            if (neighbor_distances[j] > max_dist) {
                max_dist = neighbor_distances[j];
                max_idx = j;
            }
        }

        if (z[i] < neighbor_distances[max_idx]) {
            for (int c = 0; c < REC_LENGTH - 1; c++) {
                neighbor_entries[max_idx * REC_LENGTH + c] = sandbox[i * REC_LENGTH + c];
            }
            neighbor_entries[max_idx * REC_LENGTH + REC_LENGTH - 1] = '\0';
            neighbor_distances[max_idx] = z[i];
        }
    }
}
